files.blockram.v:
module blockram(
	clk, rst,
	enb, wen, addr, din, dout
);
parameter width = 8, depth = 10, size = 1<<depth;

input clk, rst, enb, wen;
input [depth-1:0] addr;
input [width-1:0] din;
output reg [width-1:0] dout;

reg [width-1:0] ram[0:size-1];

always @(posedge clk)
	if (rst) dout <= 'hx; // uninitialized
	else if (enb)
		if (wen) ram[addr] <= din;
		else dout <= ram[addr];

endmodule

