reg [31:0] mem1[0:3]; 
 reg [31:0] mem1_do; 
 always @(posedge sys_clk) begin 
  if(we & ~wa[0]) 
  mem1[wa[2:1]] <= wd; 
  mem1_do <= mem1[ra]; 
 end 
