reg [31:0] counter; 
  always @(posedge clk) 
  if (~rst) begin 
  counter <= 0; 
  strobe_b <= 0; 
  data_b <= 0; 
  end else begin 
  counter <= counter + 1; 
  if (data_b_we & (addr_b == 65542)) 
  $display(">> Clock cycles: %d", counter); 
  if (addr_b == 65542) begin 
  strobe_b <= 1; 
  data_b <= counter; 
  end else strobe_b <= 0; 
  end 
 endmodule

