  else begin 
  assign LowLogicImm[i] = (LowMaskSel_Bot <= i[4:0]); 
  assign HighLogicImm[i] = (HighMaskSel_Bot >= i[4:0]); 
  end 
  end 
  endgenerate 
  assign LogicImm = LowLogicImm & HighLogicImm; 
