  bps_div2 = 13'd2603; 
  reg flag; 
 always @(posedge clk or negedge rst_n) 
  if(!rst_n) 
  flag <= 0; 
  else 
  if(en) 
  flag <= 1; 
  else 
  if(num == 4'd10) 
  flag <= 0; 
  reg [12:0] cnt; 
 always @(posedge clk or negedge rst_n) 
  if(!rst_n) 
  cnt <= 13'd0; 
