  cnt <= cnt + 1'b1; 
  else 
  cnt <= 13'd0; 
 always @(posedge clk or negedge rst_n) 
  if(!rst_n) 
  num <= 4'd0; 
  else 
  if(flag && sel_data) 
  num <= num +1'b1; 
  else 
  if(num == 4'd10) 
  num <= 1'd0; 
 always @(posedge clk or negedge rst_n) 
  if(!rst_n) 
  sel_data <= 1'b0; 
  else 
  if(cnt == bps_div2) 
  sel_data <= 1'b1; 
  else 
  sel_data <= 1'b0; 
