module Crc16x2Gen (Data, Complement, Crc);
input         Complement;
input  [31:0] Data;
output [15:0] Crc;

wire [15:0] ShiftChain;

wire [15:0] crc0_Data = Data[31:16];
wire [15:0] crc0_ShiftIn = 16'hffff;

wire [15:0] crc0_ShiftChain;
wire [15:0] crc0_Crc;
wire [15:0] crc0_CombCrc;

assign crc0_ShiftChain = Crc16Gen_calc(crc0_Data, 1'b0, crc0_ShiftIn);

wire [15:0] crc1_Data = Data[15:0];
wire [15:0] crc1_ShiftIn = crc0_ShiftChain;

assign Crc = Crc16Gen_calc(crc1_Data, Complement, crc1_ShiftIn);

function [15:0] Crc16Gen_calc;
    input [15:0] Data;
    input Complement;
    input [15:0] ShiftIn;
    reg [15:0] ShiftChain;
    reg [15:0] Crc;
    reg [15:0] DtXorShift = { Data[8],  Data[9],  Data[10], Data[11], Data[12], Data[13], Data[14], Data[15],
                              Data[0],  Data[1],  Data[2],  Data[3],  Data[4],  Data[5],  Data[6],  Data[7]
                            } ^ ShiftIn;
    begin
        Crc = {16{Complement}} ^ {ShiftIn[8],  ShiftIn[9],  ShiftIn[10], ShiftIn[11], 
                                  ShiftIn[12], ShiftIn[13], ShiftIn[14], ShiftIn[15],
                                  ShiftIn[0],  ShiftIn[1],  ShiftIn[2],  ShiftIn[3],  
                                  ShiftIn[4],  ShiftIn[5],  ShiftIn[6],  ShiftIn[7]};

        ShiftChain[00] = ^(DtXorShift & 16'hb111);
        ShiftChain[01] = ^(DtXorShift & 16'hd333);
        ShiftChain[02] = ^(DtXorShift & 16'ha666);
        ShiftChain[03] = ^(DtXorShift & 16'hfddd);
        ShiftChain[04] = ^(DtXorShift & 16'hfbba);
        ShiftChain[05] = ^(DtXorShift & 16'hf774);
        ShiftChain[06] = ^(DtXorShift & 16'heee8);
        ShiftChain[07] = ^(DtXorShift & 16'hddd0);
        ShiftChain[08] = ^(DtXorShift & 16'hbba0);
        ShiftChain[09] = ^(DtXorShift & 16'h7740);
        ShiftChain[10] = ^(DtXorShift & 16'hee80);
        ShiftChain[11] = ^(DtXorShift & 16'hdd00);
        ShiftChain[12] = ^(DtXorShift & 16'h0b11);
        ShiftChain[13] = ^(DtXorShift & 16'h1622);
        ShiftChain[14] = ^(DtXorShift & 16'h2c44);
        ShiftChain[15] = ^(DtXorShift & 16'h5888);

        Crc16Gen_calc = {ShiftChain[8],  ShiftChain[9],  ShiftChain[10], ShiftChain[11], 
                         ShiftChain[12], ShiftChain[13], ShiftChain[14], ShiftChain[15],
                         ShiftChain[0],  ShiftChain[1],  ShiftChain[2],  ShiftChain[3],  
                         ShiftChain[4],  ShiftChain[5],  ShiftChain[6],  ShiftChain[7]};
    end
endfunction

endmodule

