module mg_02324(Clk, Reset, InProgress, ShiftedBit, BitCounter, WriteOp, NoPre, MdcEn_n, Mdo, MdoEn);
input Clk; 
 input Reset; 
 input WriteOp; 
 input NoPre; 
 input InProgress; 
 input ShiftedBit; 
 input [6:0] BitCounter; 
 input MdcEn_n; 
 output Mdo; 
 output MdoEn; 
 wire SerialEn; 
 reg MdoEn_2d; 
 reg MdoEn_d; 
 reg MdoEn; 
 reg Mdo_2d; 
 reg Mdo_d; 
 reg Mdo; 
 assign SerialEn = WriteOp & InProgress & ( BitCounter>31 | ( ( BitCounter == 0 ) & NoPre ) ) 
  | ~WriteOp & InProgress & (( BitCounter>31 & BitCounter<46 ) | ( ( BitCounter == 0 ) & NoPre )); 
 always @ (posedge Clk or posedge Reset) 
 begin 
  if(Reset) 
  begin 
  MdoEn_2d <= 1'b0; 
  MdoEn_d <= 1'b0; 
  MdoEn <= 1'b0; 
  end 
  else 
  begin 
  if(MdcEn_n) 
  begin 
  MdoEn_2d <= SerialEn | InProgress & BitCounter<32; 
  MdoEn_d <= MdoEn_2d; 
  MdoEn <= MdoEn_d; 
  end 
  end 
 end 
 always @ (posedge Clk or posedge Reset) 
 begin 
  if(Reset) 
  begin 
  Mdo_2d <= 1'b0; 
  Mdo_d <= 1'b0; 
  Mdo <= 1'b0; 
  end 
  else 
  begin 
  if(MdcEn_n) 
  begin 
  Mdo_2d <= ~SerialEn & BitCounter<32; 
  Mdo_d <= ShiftedBit | Mdo_2d; 
  Mdo <= Mdo_d; 
  end 
  end 
 end 
 endmodule

