module rtlpp_01814 (x, y, sum, clk);  
  parameter WIDTH   = 15; 
  parameter WIDTH1  = 7;  
  parameter WIDTH2  = 8;  

  input  [WIDTH-1:0] x, y;  
  output [WIDTH-1:0] sum;  
  input              clk;  

  reg  [WIDTH1-1:0] l1, l2; 
  wire [WIDTH1-1:0] q1, r1; 
  reg  [WIDTH2-1:0] l3, l4; 
  wire [WIDTH2-1:0] r2, q2, u2; 
  reg  [WIDTH-1:0]  s;    
  wire cr1, cq1; 
  wire [WIDTH2-1:0] h2; 

  wire  clkena, ADD, ena, aset, sclr;  
  wire sset, aload, sload, aclr, ovf1, cin1; 


  assign cin1    = 0; 
  assign aclr    = 0; 
  assign ADD     = 1; 
  assign ena     = 1; 
  assign aclr    = 0;            
  assign sclr    = 0; 
  assign sset    = 0; 
  assign aload   = 0; 
  assign sload   = 0; 
  assign clkena  = 0; 
  assign aset    = 0;

  always @(posedge clk) begin
    l1[WIDTH1-1:0] <= x[WIDTH1-1:0];
    l2[WIDTH1-1:0] <= y[WIDTH1-1:0]; 
