  next_port = 8'h00; 
  end 
  end 
  PROCESS_PACKET: begin 
  hold_off_ready = 1'b0; 
  if (end_of_packet | fifo_empty) begin 
  next_state = PROCESS_LAST; 
  next_port = fifo_data[7:0]; 
  end 
  else begin 
  next_state = PROCESS_PACKET; 
  next_port = fifo_data[7:0]; 
  end 
  end 
  PROCESS_LAST: begin 
  hold_off_ready = 1'b1; 
  next_state = END_OF_PACKET_1; 
  next_port = 8'h00; 
  end 
  END_OF_PACKET_1: begin 
  hold_off_ready = 1'b1; 
  next_state = END_OF_PACKET_2; 
  next_port = 8'h00; 
  end 
  END_OF_PACKET_2: begin 
  hold_off_ready = 1'b1; 
  next_state = END_OF_PACKET_3; 
  next_port = 8'h00; 
  end 
  END_OF_PACKET_3: begin 
  hold_off_ready = 1'b1; 
  next_state = IDLE; 
  next_port = 8'h00; 
  end 
  default: begin 
  hold_off_ready = 1'b0; 
  next_state = IDLE; 
  next_port = 8'h00; 
  end 
  endcase 
 endmodule

