      if (alloc_free_target_ap_vld) begin
        alloc_free_target_ap_ack <= 1;
      end else begin
        alloc_free_target_ap_ack <= 0;
      end

      if (alloc_cmd_ap_vld) begin
        alloc_cmd_ap_ack <= 1;
      end else begin
        alloc_cmd_ap_ack <= 0;
      end

      ap_ready <= 1;
      ap_done <= 1;
    end else begin
      ap_idle <= 1;
      ap_ready <= 0;
      ap_done <= 0;
    end
  end
end

endmodule

