module origen_088952 #(
    parameter DEPTH = 16,
    parameter SIZE = 8
)(
    input wire Wrclk, Rdclk, Rst,
    input wire Wren, Rden,
    input wire [SIZE-1:0] Datain,
    output reg [SIZE-1:0] Dataout,
    output reg Full, Empty
);

reg [SIZE-1:0] memory [0:DEPTH-1];
reg [$clog2(DEPTH)-1:0] write_ptr, read_ptr;
reg read_done, write_done;
reg direction;

`ifdef LIFO
    always @(posedge Wrclk or posedge Rst) begin
        if (Rst) begin
            write_ptr <= 0;
            Full <= 0;
            Empty <= 1;
        end else if (Wren && !Rden && !Full) begin
            memory[write_ptr] <= Datain;
            write_ptr <= write_ptr + 1;
            Empty <= 0;
            Full <= (write_ptr == DEPTH - 1);
        end else if (Rden && !Wren && !Empty) begin
            write_ptr <= write_ptr - 1;
            Full <= 0;
            Empty <= (write_ptr == 1);
        end else if (Wren && Rden && !Empty) begin
            memory[write_ptr-1] <= Datain;
        end
    end

    always @(posedge Rdclk) begin
        if (!Empty) begin
            Dataout <= memory[write_ptr-1];
        end
    end

`elsif FIFO
    always @(posedge Wrclk or posedge Rst) begin
        if (Rst) begin
            write_ptr <= 0;
            write_done <= 0;
            Full <= 0;
        end else if (Wren && !Full) begin
            memory[write_ptr] <= Datain;
            write_ptr <= (write_ptr == DEPTH-1) ? 0 : write_ptr + 1;
            write_done <= 1;
            Full <= (write_ptr == read_ptr - 1) || (write_ptr == DEPTH-1 && read_ptr == 0);
        end else begin
            write_done <= 0;
        end
    end

    always @(posedge Rdclk or posedge Rst) begin
        if (Rst) begin
            read_ptr <= 0;
            read_done <= 0;
            Empty <= 1;
            direction <= 0;
        end else if (Rden && !Empty) begin
            Dataout <= memory[read_ptr];
            read_ptr <= (read_ptr == DEPTH-1) ? 0 : read_ptr + 1;
            read_done <= 1;
            Empty <= (read_ptr == write_ptr - 1) || (read_ptr == DEPTH-1 && write_ptr == 0);
        end else begin
            read_done <= 0;
        end
    end

    always @(posedge Wrclk or posedge Rdclk) begin
        if (write_done && !read_done)
            direction <= 1;
        else if (!write_done && read_done)
            direction <= 0;
    end

    always @(*) begin
        if (write_ptr == read_ptr)
            Empty = !direction;
        else
            Empty = 0;

        if ((write_ptr == read_ptr - 1) || (write_ptr == DEPTH-1 && read_ptr == 0))
            Full = 1;
        else
            Full = 0;
    end
`endif

endmodule

