module autovcoder_002979 (
    input             adc_clk,
    input             rst,
    input      [11:0] adc_data,
    output reg        adc_buf_wr,
    output     [11:0] adc_buf_addr,
    output     [ 7:0] adc_buf_data
);

  `define TRIGGER

  localparam S_IDLE = 0;
  localparam S_SAMPLE = 1;
  localparam S_WAIT = 2;

  reg signed [11:0] adc_data_reve;
  reg signed [12:0] adc_data_offset;
  reg [7:0] adc_data_narrow;
  reg [7:0] adc_data_narrow_d0;
  reg [10:0] sample_cnt;
  reg [31:0] wait_cnt;
  reg [2:0] state;
  assign adc_buf_addr = sample_cnt;
  assign adc_buf_data = adc_data_narrow;
  always @(posedge adc_clk or posedge rst) begin
    if (rst == 1'b1) adc_data_reve <= 12'd0;
    else
      adc_data_reve <= {
        adc_data[0],
        adc_data[1],
        adc_data[2],
        adc_data[3],
        adc_data[4],
        adc_data[5],
        adc_data[6],
        adc_data[7],
        adc_data[8],
        adc_data[9],
        adc_data[10],
        adc_data[11]
      };
  end

  always @(posedge adc_clk or posedge rst) begin
    if (rst == 1'b1) adc_data_offset <= 13'd0;
    else adc_data_offset <= {adc_data_reve[11], adc_data_reve} + 13'd2048;
  end

  always @(posedge adc_clk or posedge rst) begin
    if (rst == 1'b1) adc_data_narrow <= 8'd0;
    else adc_data_narrow <= adc_data_offset[11:4];
  end

  always @(posedge adc_clk or posedge rst) begin
    if (rst == 1'b1) adc_data_narrow_d0 <= 8'd0;
    else adc_data_narrow_d0 <= adc_data_narrow_d0;
  end
  always @(posedge adc_clk or posedge rst) begin
    if (rst == 1'b1) begin
      state <= S_IDLE;
      wait_cnt <= 32'd0;
      sample_cnt <= 11'd0;
      adc_buf_wr <= 1'b0;
    end else
      case (state)
        S_IDLE: begin
          state <= S_SAMPLE;
        end
        S_SAMPLE: begin
          if (sample_cnt == 11'd1023) begin
            sample_cnt <= 11'd0;
            adc_buf_wr <= 1'b0;
            state <= S_WAIT;
          end else begin
            sample_cnt <= sample_cnt + 11'd1;
            adc_buf_wr <= 1'b1;
          end

        end
        S_WAIT: begin
`ifdef TRIGGER
          if (adc_data_narrow_d0 < 8'd127 && adc_data_narrow >= 8'd127) state <= S_SAMPLE;
`else
          if (wait_cnt == 32'd25_000_000) begin
            state <= S_SAMPLE;
            wait_cnt <= 32'd0;
          end else begin
            wait_cnt <= wait_cnt + 32'd1;
          end
`endif
        end
        default: state <= S_IDLE;
      endcase
  end

endmodule

