    output reg [6:0] Segout,
    output reg SG1, SG2, SG3, SG4
);

reg [1:0] Count;

always @(posedge CP) begin
    Count <= Count + 1;
end

always @(*) begin
    case (Count)
        2'b00: begin
            SG1 = 1'b1;
            SG2 = 1'b0;
            SG3 = 1'b0;
            SG4 = 1'b0;
            case (BCD1)
