    output reg arithmetic_negative,
    output reg [1:0] logic_ctrl,
    output reg [1:0] shift_ctrl,
    output reg comparer_signed_compare,
    output reg [2:0] comparer_compare_select,
    output reg [1:0] ALU_S_select
);

always @(*) begin
    case (ctrl_in)
