            comparer_compare_select = 3'b001;
            ALU_S_select = 2'b01;
        end
        4'b0101: begin
            arithmetic_negative = 1'b0;
            logic_ctrl = 2'b11;
            shift_ctrl = 2'b00;
            comparer_signed_compare = 1'b0;
            comparer_compare_select = 3'b001;
            ALU_S_select = 2'b01;
        end
        4'b0110: begin
            arithmetic_negative = 1'b0;
            logic_ctrl = 2'b00;
            shift_ctrl = 2'b00;
            comparer_signed_compare = 1'b0;
            comparer_compare_select = 3'b001;
            ALU_S_select = 2'b10;
        end
        4'b0111: begin
            arithmetic_negative = 1'b0;
            logic_ctrl = 2'b00;
            shift_ctrl = 2'b01;
            comparer_signed_compare = 1'b0;
            comparer_compare_select = 3'b001;
            ALU_S_select = 2'b10;
        end
        4'b1000: begin
            arithmetic_negative = 1'b0;
            logic_ctrl = 2'b00;
            shift_ctrl = 2'b10;
            comparer_signed_compare = 1'b0;
            comparer_compare_select = 3'b001;
            ALU_S_select = 2'b10;
        end
        4'b1010: begin
            arithmetic_negative = 1'b0;
