		if(Reset_L == 0) 
			CurrentState <= Reset;
		else
			CurrentState <= NextState;	
	end

	always @(posedge Clock)
	begin
		if(BurstCounterReset_L == 0) 						
			BurstCounter <= 0;
		else
			BurstCounter <= BurstCounter + 1;
