		ValidBit_WE_L                    <= 1;									
		ValidBitOut_H                    <= 0;
		DramSelectFromCache_L            <= 1;									
		WordAddress                      <= 0;									

		BurstCounterReset_L              <= 1;									
		NextState                        <= Idle ;							

		if(CurrentState == Reset) begin	  								
			BurstCounterReset_L            <= 0;							
			NextState                      <= InvalidateCache;				
