module origen_107595 (
    input logic Clk,
    input logic Reset,
    input logic [15:0] Bus,
    input logic LD_CC,
    output logic n,
    output logic z,
    output logic p
);

    logic n_Next, z_Next, p_Next;

    always_ff @(posedge Clk or posedge Reset) begin
        if (Reset) begin
            n <= 1'b0;
            z <= 1'b0;
            p <= 1'b0;
        end else begin
            n <= n_Next;
