reg r_sign;
reg [31:0] sub_add;
reg [4:0] count;

wire [31:0] dividend_temp, divisor_temp;

assign dividend_temp = (dividend[31]) ? -dividend : dividend;
assign divisor_temp = (divisor[31]) ? -divisor : divisor;

always @(posedge clock or posedge reset) begin
    if (reset) begin
        reg_q <= 0;
        reg_r <= 0;
        reg_b <= 0;
        r_sign <= 0;
        count <= 0;
        busy <= 0;
    end
    else if (start) begin
        reg_r <= 0;
        r_sign <= 0;
        reg_q <= dividend_temp;
        reg_b <= divisor_temp;
        busy <= 1;
        count <= 0;
