        sub_add <= (r_sign) ? reg_r + reg_b : reg_r - reg_b;
        reg_r <= sub_add;
        r_sign <= sub_add[31];
        reg_q <= {reg_q[30:0], ~sub_add[31]};
        count <= count + 1;
        busy <= (count == 31) ? 0 : 1;
    end
end

always @* begin
    q = (dividend[31] ^ divisor[31]) ? -reg_q : reg_q;
    r = (dividend[31]) ? -reg_r : reg_r;
