            if (x == WIDTH - 1) begin
                x <= 0;
                if (y == HEIGHT - 1) begin
                    y <= 0;
                    next_frame <= 1;
                    reset <= 1;
                end else begin
                    y <= y + 1;
                end
            end else begin
                x <= x + 1;
            end
        end
    end else if (next_frame) begin
        next_frame <= 0;
    end
end

always @(*) begin
    if ((y[0] && flip_odd) || (!y[0] && flip_even)) begin
        array_x = WIDTH - 1 - x;
