    output reg [2:0] r_lights,
    output reg [1:0] c_lights
);

reg brake_active;

localparam IDLE = 2'b00, BRAKE1 = 2'b01, BRAKE2 = 2'b10;
reg [1:0] state;

always @(posedge clock) begin
    case (state)
        IDLE: begin
            if (brake) begin
                state <= BRAKE1;
                brake_active <= 1;
