                brake_active <= 0;
            end
        end
        BRAKE1: begin
            if (!brake) begin
                state <= BRAKE2;
            end
        end
        BRAKE2: begin
            if (!brake) begin
                state <= IDLE;
            end else begin
                state <= BRAKE1;
            end
        end
    endcase
end

always @(*) begin
    if (brake_active) begin
        l_lights = ~l_signal;
        r_lights = ~r_signal;
        c_lights = 2'b11;
    end else begin
        l_lights = l_signal;
        r_lights = r_signal;
        c_lights = 2'b00;
