module painter(
    input wire clock,
    input wire resetn,
    input wire [19199:0] image,
    input wire [2:0] color_background,
    input wire [2:0] color_foreground,
    output reg [7:0] x,
    output reg [6:0] y,
    output reg [2:0] color
);

    reg [14:0] count;

    always @(posedge clock or negedge resetn) begin
        if (!resetn) begin
            count <= 15'd0;
            x <= 8'd0;
            y <= 7'd119;
            color <= color_background;
        end else begin
            if (count == 15'd19199) begin
                count <= 15'd0;
            end else begin
