    output reg [4:0] IDEXRs1,
    output reg [4:0] IDEXRs2,

    //br_pred
    input br_pred_d,
    output reg br_pred_e
);

  always @(posedge clk) begin
    if (eFlush) begin
      IDEXpc <= 0;
