module autovcoder_143231 (
    input wire clk,               // System clock
    input wire reset,             // System reset
    input wire start,             // Start signal
    input wire [6:0] slave_addr,  // 7-bit slave address
    input wire [7:0] reg_addr,    // Register address
    input wire [7:0] data,        // Data to write
    output reg scl,               // I2C clock line
    output reg sda,               // I2C data line
    output reg done               // Operation done signal
);

reg [3:0] state;
reg [3:0] count;

localparam IDLE = 4'd0,
           START = 4'd1,
           SLAVE_ADDR = 4'd2,
           ACK_ADDR = 4'd3,
           REG_ADDR = 4'd4,
           ACK_REG = 4'd5,
           DATA = 4'd6,
           ACK_DATA = 4'd7,
           STOP = 4'd8;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        scl <= 1;
        sda <= 1;
        state <= IDLE;
        done <= 0;
        count <= 0;
    end else begin
        case (state)
            IDLE: begin
                if (start) begin
                    scl <= 1;
                    sda <= 1;
                    done <= 0;
                    state <= START;
                end
            end

            START: begin
                sda <= 0; // Start condition
                state <= SLAVE_ADDR;
            end

            SLAVE_ADDR: begin
                sda <= slave_addr[count]; // Send slave address
                count <= count + 1;
                if (count == 7) begin
                    state <= ACK_ADDR;
                end
            end

            ACK_ADDR: begin
                // Wait for the acknowledgment (not implemented as a signal)
                state <= REG_ADDR;
                count <= 0;
            end

            REG_ADDR: begin
                sda <= reg_addr[count]; // Send register address
                count <= count + 1;
                if (count == 7) begin
                    state <= ACK_REG;
                end
            end

            ACK_REG: begin
                // Wait for the acknowledgment (not implemented as a signal)
                state <= DATA;
                count <= 0;
            end

            DATA: begin
                sda <= data[count]; // Send data
                count <= count + 1;
                if (count == 7) begin
                    state <= ACK_DATA;
                end
            end

            ACK_DATA: begin
                // Wait for the acknowledgment (not implemented as a signal)
                state <= STOP;
            end

            STOP: begin
                sda <= 1; // Stop condition
                done <= 1;
                state <= IDLE;
            end

            default: state <= IDLE;
        endcase
    end
end

endmodule

