        if (!reset) begin
            i <= 0;
            cnt <= 0;
            cnt1 <= 0;
            addr_a <= 0;
            addr_b <= 0;
            data_in <= 0;
            en_a <= 0;
            en_b <= 0;
            we_a <= 4'b0000;
            doutb <= 32'h0;
        end else begin
            case (i)
                0: begin // Initialization
                    en_a <= 1;
                    we_a <= 4'b1111;
                    i <= 1;
