                        if (cnt1 == 4) begin
                            cnt <= cnt + 1;
                            cnt1 <= 0;
                        end else begin
                            cnt1 <= cnt1 + 1;
                        end
                    end else begin
                        i <= 2;
                        cnt <= 0;
                    end
                end
                2: begin // Transition to Read
                    we_a <= 4'b0000;
                    en_b <= 1;
                    i <= 3;
                end
                3: begin // Read Operation
                    if (cnt < 10) begin
                        addr_b <= addr_b + 1;
                        cnt <= cnt + 1;
                    end else begin
                        i <= 4;
                        cnt <= 0;
                    end
                end
                4: begin // Read Reset
                    addr_b <= 0;
                    i <= 3;
                end
            endcase
        end
    end

    // RAM instantiation would go here
