        4'b0000: begin
            if (start) begin
                c <= 1'b0;
                Acc <= 4'b0000;
                Q <= a;
                State <= 4'b0001;
            end
        end
        4'b0001: begin
            if (Q[0]) begin
                Acc <= m1 + b;
                c <= Acc[0];
            end else begin
                Acc <= m2;
                c <= 1'b0;
            end
            Q <= m3;
            State <= 4'b0010;
        end
        4'b0010: begin
            Acc <= m2;
            Q <= m4;
            State <= 4'b0011;
        end
        4'b0011: begin
            if (Q[0]) begin
                Acc <= m1 + b;
                c <= Acc[0];
            end else begin
                Acc <= m2;
                c <= 1'b0;
            end
            Q <= m3;
            State <= 4'b0100;
        end
        4'b0100: begin
            Acc <= m2;
            Q <= m4;
            State <= 4'b0101;
        end
        4'b0101: begin
            if (Q[0]) begin
                Acc <= m1 + b;
                c <= Acc[0];
            end else begin
                Acc <= m2;
                c <= 1'b0;
            end
            Q <= m3;
            State <= 4'b0110;
        end
        4'b0110: begin
            Acc <= m2;
            Q <= m4;
            State <= 4'b0111;
        end
        4'b0111: begin
            if (Q[0]) begin
                Acc <= m1 + b;
                c <= Acc[0];
            end else begin
                Acc <= m2;
                c <= 1'b0;
            end
            Q <= m3;
            State <= 4'b1000;
        end
        4'b1000: begin
            Acc <= m2;
            Q <= m4;
            State <= 4'b1001;
        end
        4'b1001: begin
            flag <= 1'b1;
            mul <= {c, Acc, Q};
        end
        default: State <= 4'b0000;
    endcase
end

endmodule

