module origen_142556 (
    input wire clk,
    input wire rst,
    input wire clear,
    input wire [7:0] in_data,
    input wire in_sof,
    input wire in_eof,
    input wire in_src_rdy,
    output wire in_dst_rdy,
    output wire [18:0] out_data,
    output wire out_sof,
    output wire out_eof,
    output wire out_src_rdy,
    input wire out_dst_rdy
);

    // Parameters
    localparam XFER_EMPTY = 2'b00;
    localparam XFER_HALF = 2'b01;
    localparam XFER_HALF_WRITE = 2'b10;

    // Internal registers
    reg [1:0] state;
    reg [7:0] input_reg;
    reg hold_sof;
    reg [18:0] output_reg;

    // FIFOs
    reg [7:0] input_fifo [3:0];
    reg [1:0] input_fifo_wr_ptr, input_fifo_rd_ptr;
    reg [18:0] output_fifo [3:0];
    reg [1:0] output_fifo_wr_ptr, output_fifo_rd_ptr;

    // FIFO status
    wire input_fifo_empty = (input_fifo_wr_ptr == input_fifo_rd_ptr);
    wire input_fifo_full = ((input_fifo_wr_ptr + 1) & 2'b11) == input_fifo_rd_ptr;
    wire output_fifo_empty = (output_fifo_wr_ptr == output_fifo_rd_ptr);
    wire output_fifo_full = ((output_fifo_wr_ptr + 1) & 2'b11) == output_fifo_rd_ptr;

    // Input FIFO write
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            input_fifo_wr_ptr <= 2'b00;
        end else if (clear) begin
            input_fifo_wr_ptr <= 2'b00;
        end else if (in_src_rdy && !input_fifo_full) begin
            input_fifo[input_fifo_wr_ptr] <= in_data;
            input_fifo_wr_ptr <= (input_fifo_wr_ptr + 1) & 2'b11;
        end
    end

    // Input FIFO read
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            input_fifo_rd_ptr <= 2'b00;
            input_reg <= 8'b0;
        end else if (clear) begin
            input_fifo_rd_ptr <= 2'b00;
            input_reg <= 8'b0;
        end else if (!input_fifo_empty && state == XFER_EMPTY) begin
            input_reg <= input_fifo[input_fifo_rd_ptr];
            input_fifo_rd_ptr <= (input_fifo_rd_ptr + 1) & 2'b11;
        end
    end

    // State machine
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= XFER_EMPTY;
            hold_sof <= 1'b0;
            output_reg <= 19'b0;
        end else if (clear) begin
            state <= XFER_EMPTY;
            hold_sof <= 1'b0;
            output_reg <= 19'b0;
        end else begin
            case (state)
                XFER_EMPTY: begin
                    if (!input_fifo_empty) begin
                        state <= XFER_HALF;
                        hold_sof <= in_sof;
                        output_reg[7:0] <= input_reg;
                    end
                end
                XFER_HALF: begin
                    if (!input_fifo_empty && !output_fifo_full) begin
                        state <= XFER_EMPTY;
                        output_reg[18:8] <= {3'b0, input_reg};
                        output_fifo[output_fifo_wr_ptr] <= output_reg;
                        output_fifo_wr_ptr <= (output_fifo_wr_ptr + 1) & 2'b11;
                    end else if (!input_fifo_empty) begin
                        state <= XFER_HALF_WRITE;
                        output_reg[18:8] <= {3'b0, input_reg};
                    end
                end
                XFER_HALF_WRITE: begin
                    if (!output_fifo_full) begin
                        state <= XFER_EMPTY;
                        output_fifo[output_fifo_wr_ptr] <= output_reg;
                        output_fifo_wr_ptr <= (output_fifo_wr_ptr + 1) & 2'b11;
                    end
                end
            endcase
        end
    end

    // Output FIFO read
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            output_fifo_rd_ptr <= 2'b00;
        end else if (clear) begin
            output_fifo_rd_ptr <= 2'b00;
        end else if (!output_fifo_empty && out_dst_rdy) begin
            output_fifo_rd_ptr <= (output_fifo_rd_ptr + 1) & 2'b11;
        end
    end

    // Output assignments
    assign in_dst_rdy = !input_fifo_full;
    assign out_data = output_fifo[output_fifo_rd_ptr];
    assign out_sof = hold_sof && (state == XFER_HALF || state == XFER_HALF_WRITE);
    assign out_eof = in_eof && (state == XFER_HALF || state == XFER_HALF_WRITE);
    assign out_src_rdy = !output_fifo_empty;

endmodule

