module origen_012132(
    input wire clk,
    input wire go_reset_data,
    input wire go_choose_node,
    input wire go_check_node,
    input wire go_do_ops,
    input wire ld_memory,
    output reg data_reset_done,
    output reg node_chosen,
    output reg all_done,
    output reg node_checked,
    output reg node_valid,
    output reg ops_done,
    output reg memory_loaded,
    input wire [31:0] numNodes,
    input wire [31:0] numRefNodes,

    // Memory interfaces
    output reg [31:0] nodeHeads_address,
    input wire [127:0] nodeHeads_q,
    output reg [31:0] matrix_address,
    input wire [31:0] matrix_q,
    output reg [31:0] nodeVoltage_address,
    output reg [31:0] nodeVoltage_data,
    output reg nodeVoltage_wren,
    input wire [31:0] nodeVoltage_q,

    // Arithmetic units
    output reg [31:0] adder_a,
    output reg [31:0] adder_b,
    input wire [31:0] adder_result,
    output reg [31:0] multiplier_a,
    output reg [31:0] multiplier_b,
    input wire [31:0] multiplier_result,
    output reg [31:0] fp_to_int_a,
    input wire [31:0] fp_to_int_result
);

    // Constants
    localparam [31:0] EXPAND = 32'h3F800000;    // 1.0 in float
    localparam [31:0] REDUCE = 32'h3F000000;    // 0.5 in float
    localparam [31:0] IDENTITY = 32'h3F800000;  // 1.0 in float

    // Internal registers
    reg [31:0] nodeLoopIndex;
    reg [31:0] nodeData [0:3];
    reg [31:0] matrixData;
    reg [31:0] voltageData;
    reg [3:0] ram_delay;

    // State machine
    reg [2:0] state;
    localparam RESET = 3'd0,
               CHOOSE_NODE = 3'd1,
               CHECK_NODE = 3'd2,
               DO_OPS = 3'd3,
               LOAD_MEMORY = 3'd4;

    always @(posedge clk) begin
        case (state)
            RESET: begin
                if (go_reset_data) begin
                    nodeLoopIndex <= 32'd0;
                    data_reset_done <= 1'b0;
                    node_chosen <= 1'b0;
                    all_done <= 1'b0;
                    node_checked <= 1'b0;
                    node_valid <= 1'b0;
                    ops_done <= 1'b0;
                    memory_loaded <= 1'b0;
                    ram_delay <= 4'd0;
                    state <= CHOOSE_NODE;
                end
            end

            CHOOSE_NODE: begin
                if (go_choose_node) begin
                    if (nodeLoopIndex < numNodes) begin
                        nodeHeads_address <= nodeLoopIndex;
                        ram_delay <= 4'd1;
                        state <= CHECK_NODE;
                    end else begin
                        all_done <= 1'b1;
                        state <= RESET;
                    end
                end
            end

            CHECK_NODE: begin
                if (go_check_node) begin
                    if (ram_delay > 0) begin
                        ram_delay <= ram_delay - 1;
                    end else begin
                        nodeData[0] <= nodeHeads_q[31:0];
                        nodeData[1] <= nodeHeads_q[63:32];
                        nodeData[2] <= nodeHeads_q[95:64];
                        nodeData[3] <= nodeHeads_q[127:96];
                        node_checked <= 1'b1;
                        node_valid <= (nodeData[0] != 32'd0);
                        state <= DO_OPS;
                    end
                end
            end

            DO_OPS: begin
                if (go_do_ops) begin
                    if (node_valid) begin
                        // Perform matrix operations
                        matrix_address <= nodeData[1];
                        nodeVoltage_address <= nodeData[2];
                        ram_delay <= 4'd1;
                        state <= LOAD_MEMORY;
                    end else begin
                        nodeLoopIndex <= nodeLoopIndex + 1;
                        ops_done <= 1'b1;
                        state <= CHOOSE_NODE;
                    end
                end
            end

            LOAD_MEMORY: begin
                if (ld_memory) begin
                    if (ram_delay > 0) begin
                        ram_delay <= ram_delay - 1;
                    end else begin
                        matrixData <= matrix_q;
                        voltageData <= nodeVoltage_q;

                        // Perform calculations
                        multiplier_a <= matrixData;
                        multiplier_b <= voltageData;

                        adder_a <= multiplier_result;
                        adder_b <= nodeData[3];

                        fp_to_int_a <= adder_result;

                        // Update node voltage
                        nodeVoltage_address <= nodeData[2];
                        nodeVoltage_data <= fp_to_int_result;
                        nodeVoltage_wren <= 1'b1;

                        memory_loaded <= 1'b1;
                        state <= DO_OPS;
                    end
                end
            end
        endcase
    end

endmodule

