module origen_141145 (
    input wire clk,
    input wire start,
    input wire [3:0] multiplier_address,
    input wire [3:0] multiplicand_address,
    output reg [7:0] p,
    output reg done
);

reg [3:0] multiplier;
reg [3:0] multiplicand;
reg [3:0] adder_out;
reg [7:0] shift_reg;
reg [2:0] count;
reg add_en;

// 4-bit binary adder
always @(*) begin
    if (add_en)
        adder_out = shift_reg[7:4] + multiplicand;
    else
        adder_out = shift_reg[7:4];
end

// Main state machine
always @(posedge clk) begin
    if (start) begin
        multiplier <= multiplier_address;
        multiplicand <= multiplicand_address;
        shift_reg <= 8'b0;
        count <= 3'b0;
        done <= 1'b0;
        add_en <= 1'b0;
    end else if (!done) begin
        if (count < 4) begin
            add_en <= multiplier[0];
            shift_reg <= {adder_out, shift_reg[3:1]};
            multiplier <= {1'b0, multiplier[3:1]};
            count <= count + 1;
        end else begin
            p <= shift_reg;
            done <= 1'b1;
        end
    end
end

endmodule

