    input wire reset,
    input wire ena,
    output reg pm,
    output wire [7:0] hh,
    output wire [7:0] mm,
    output wire [7:0] ss
);

    wire [3:0] sec_ones, sec_tens, min_ones, min_tens;
    wire sec_ones_ena, sec_tens_ena, min_ones_ena, min_tens_ena, hours_ena;

