        .clk(clk),
        .reset(reset),
        .ena(sec_ones_ena),
        .q(sec_tens),
        .overflow(sec_tens_ena)
    );

    // Minutes ones
    cnt #(4'h0, 4'h9) cnt_min_ones (
        .clk(clk),
        .reset(reset),
        .ena(sec_tens_ena),
        .q(min_ones),
        .overflow(min_ones_ena)
    );

    // Minutes tens
    cnt #(4'h0, 4'h5) cnt_min_tens (
        .clk(clk),
        .reset(reset),
        .ena(min_ones_ena),
        .q(min_tens),
        .overflow(min_tens_ena)
    );

    // Hours
    cnt_hour cnt_hours (
        .clk(clk),
        .reset(reset),
        .ena(min_tens_ena),
        .q(hh),
