module cnt #(
    parameter START = 4'h0,
    parameter END = 4'h9
)(
    input wire clk,
    input wire reset,
    input wire ena,
    output reg [3:0] q,
    output wire overflow
);

    always @(posedge clk or posedge reset) begin
        if (reset)
            q <= START;
        else if (ena) begin
            if (q == END)
                q <= START;
            else
                q <= q + 1'b1;
        end
    end

    assign overflow = (q == END) & ena;

endmodule

module cnt_hour(
    input wire clk,
    input wire reset,
    input wire ena,
    output reg [7:0] q,
    output reg pm
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            q <= 8'h12;
            pm <= 1'b0;
        end else if (ena) begin
            if (q == 8'h12)
                q <= 8'h01;
            else if (q[3:0] == 4'h9)
                q <= {q[7:4] + 1'b1, 4'h0};
            else
                q <= {q[7:4], q[3:0] + 1'b1};

            if (q == 8'h11)
                pm <= ~pm;
        end
    end

endmodule

